queries.queryString:
_index="sumologic_volume"
AND _sourcecategory = "granular_volume"

{{keywords}}
//// built in
| json field=_raw "messageTier" as datatier | where datatier matches "{{datatier}}"
| json field=_raw "sizeInBytes" as bytes  
| json field=_raw "messageCount" as events 
| json field=_raw "viewName"  as index | where index matches "{{partition}}"
//
//// defined in feature flag
| json field=_raw "collectorName" as collector nodrop | where collector matches "{{collector}}"
| json field=_raw "sourceCategory"  nodrop | where sourcecategory matches "{{sourcecategory}}"
| json field=_raw "bladeName" as source nodrop

|  sum(events) as events by datatier,index,sourcecategory
| if(index="Default Index","sumologic_default",index) as index
| concat("_index=",index," _sourcecategory=",replace(sourcecategory," ","?")) as query_scope

| limit 1000 | sort sourcecategory asc, index asc

// prepare the category strings

| concat("_index=",index) as  i
| concat("_sourcecategory=",sourcecategory) as sc
//| concat("\n_collector=",collector) as c
//| concat("\n_source=",source) as s 

// fix if they put a space in their stuff
| replace(i," ","?") as i
| replace(sc," ","?") as sc
//| replace(c," ","?") as c
//| replace(s," ","?") as s

// create one meta to avoid the 10 param limit on concat using multiple concats.
| i as meta
| concat (meta,"\n ",sc) as meta
//| concat (meta,"\n // ",c,"\n //",s," ") as meta
| trim(meta) as meta

| tourl(concat("https://{{my_instance_name}}/log-search/create?query=",urlencode(meta)),"»»") as  %"Open in Search" 
| fields -i,sc,meta

_index="sumologic_volume"
AND _sourcecategory = "granular_volume"

{{keywords}}
//// built in
| json field=_raw "messageTier" as datatier | where datatier matches "{{datatier}}"
| json field=_raw "sizeInBytes" as bytes  
| json field=_raw "messageCount" as events 
| json field=_raw "viewName"  as index | where index matches "{{partition}}"
//
//// defined in feature flag
| json field=_raw "collectorName" as collector nodrop | where collector matches "{{collector}}"
| json field=_raw "sourceCategory"  nodrop | where sourcecategory matches "{{sourcecategory}}"
| json field=_raw "bladeName" as source nodrop
| timeslice 
| sum(events) as events by _timeslice,{{graph_grouping}} | transpose row _timeslice column {{graph_grouping}}
